// Import necessary libraries
const { ethers } = require("ethers");

// Define ERC20 token contract addresses
const token1Address = "0x...";
const token2Address = "0x...";

// Define DEX contract address
const dexAddress = "0x...";

// Create provider and signer
const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

// Define token contracts
const token1 = new ethers.Contract(token1Address, ["function approve(address, uint256) public"], signer);
const token2 = new ethers.Contract(token2Address, ["function approve(address, uint256) public"], signer);

// Define DEX contract
const dex = new ethers.Contract(dexAddress, ["function swapTokens(address, uint256, address, uint256) public"], signer);

// Function to approve maximum tokens for DEX contract
async function approveTokens() {
  await token1.approve(dexAddress, ethers.constants.MaxUint256);
  await token2.approve(dexAddress, ethers.constants.MaxUint256);
}

// Function to swap tokens
async function swapTokens(tokenIn, amountIn, tokenOut) {
  await approveTokens();
  await dex.swapTokens(tokenIn, amountIn, tokenOut, signer.address);
}